from __future__ import annotations
from typing import Any


def build_answers(ctx: dict[str, Any]) -> dict[str, str]:
    return {'dna_change': f"DNA changed from {ctx['_pct'](ctx['overall_dna_previous'])} to {ctx['_pct'](ctx['overall_dna_recent'])}. The largest observed contribution is {ctx['top_dna']['dimension']}={ctx['top_dna']['segment']} ({ctx['_pct'](ctx['top_dna']['total_contribution'], 2)} percentage-point contribution), but this decomposition is not causal.", 'predictive_vs_causal': f"The strongest fitted predictive term is {(ctx['top_feature']['feature'] if ctx['top_feature'] is not None else 'not available')} using {(ctx['top_feature']['method'] if ctx['top_feature'] is not None else 'no model explanation')}. It predicts risk conditional on the model; it does not show that changing the feature would change attendance.", 'model_baseline': f"The champion is {ctx['best_model']['model']} with PR-AUC {ctx['_fmt'](ctx['best_model']['pr_auc'], 3)}, Brier {ctx['_fmt'](ctx['best_model']['brier_score'], 3)} and precision@{int(ctx['best_model']['top_k'])} {ctx['_pct'](ctx['best_model']['precision_at_k'])}. The alternative {ctx['baseline_model']['model']} has PR-AUC {ctx['_fmt'](ctx['baseline_model']['pr_auc'], 3)} and Brier {ctx['_fmt'](ctx['baseline_model']['brier_score'], 3)}.", 'calibration': f"The latest monitoring month has observed DNA {ctx['_pct'](ctx['latest_monitoring']['observed_dna_rate'])}, mean prediction {ctx['_pct'](ctx['latest_monitoring']['mean_predicted_probability'])} and absolute gap {ctx['_pct'](ctx['latest_monitoring']['absolute_calibration_gap'])}. The configured review level is {ctx['_pct'](ctx['operations_config']['thresholds']['attendance_calibration_gap'])}.", 'threshold_policy': f"At weekly capacity {ctx['default_capacity']}, a synthetic review option is minimum probability {ctx['_pct'](ctx['threshold_choice']['minimum_probability'], 0)}: {int(ctx['threshold_choice']['selected_count'])} selected, precision {ctx['_pct'](ctx['threshold_choice']['precision'])}, recall {ctx['_pct'](ctx['threshold_choice']['recall'])}, and route/service selection gaps {ctx['_pct'](ctx['threshold_choice']['funding_route_selection_gap'])}/{ctx['_pct'](ctx['threshold_choice']['service_group_selection_gap'])}.", 'subgroup_model': f"The subgroup Brier-score range is {ctx['_fmt'](ctx['subgroup_gap'], 3)} across the current funding/service audit. I would not approve use from aggregate performance alone; prevalence, calibration, sample size and selection rate all need review.", 'model_action_rule': f"The challenger promotion flag is {ctx['reliable_challenger']}. Retrain or recalibrate only after validating data, calibration, ranking, subgroup behaviour and workflow changes; suspend model-led probability decisions if calibration cannot be validated.", 'permitted_actions': 'The model is limited to standard or additional reminders, confirmation and easier rescheduling. It must not determine diagnosis, treatment, eligibility, automatic cancellation or lower care priority.'}
